If you do this part in a separate function, you can determine `indeterminate` and `checked` without the 2 extra loops.

```ts
private _getFolder() {
	const templates = [];
	let noChecked = 0;
	let checked = false;
    let indeterminate = false
	this.folders.forEach(item => {template.push(html`...`); if (item.checked) noChecked++});
	
    if (noChecked === this.folder.length) checked = true
	else if (noChecked) indeterminate = true
    return {templates, checked, indeterminate}
}
```

